//! Kernel entrypoint with architecture-specific wiring.
#![deny(missing_docs)]
#![deny(warnings)]
#![no_std]
#![no_main]
#![feature(alloc_error_handler)]

#[macro_use]
extern crate bitflags;
#[macro_use]
extern crate log;

extern crate alloc;
extern crate arch;

#[macro_use]
mod console;

#[macro_use]
mod logging;

#[cfg_attr(target_arch = "riscv64", path = "boards/qemu.rs")]
#[cfg_attr(target_arch = "loongarch64", path = "boards/qemu_la.rs")]
mod board;

pub mod config;
/// Device drivers and device manager glue.
pub mod drivers;
/// File system layer (shared across all architectures).
pub mod fs;
pub mod lang_items;
pub mod mm;
/// Network subsystem (smoltcp-based, loopback on all arches, external net on RISC-V).
pub mod net;
/// Platform-level IRQ and device dispatch.
pub mod platform;
pub mod sync;
pub mod syscall;
pub mod task;
pub mod timer;
pub mod trap;

mod boot;

// ---------------------------------------------------------------------------
// DEV_NON_BLOCKING_ACCESS — lives in the kernel, not in the arch crate.
// Used by the virtio block driver to switch between polling / interrupt I/O.
// ---------------------------------------------------------------------------

#[cfg(target_arch = "riscv64")]
use sync::UPIntrFreeCell;

#[cfg(target_arch = "riscv64")]
lazy_static::lazy_static! {
    /// Switch between polling and interrupt-driven block I/O.
    pub static ref DEV_NON_BLOCKING_ACCESS: UPIntrFreeCell<bool> =
        unsafe { UPIntrFreeCell::new(false) };
}

// ---------------------------------------------------------------------------
// ArchInterface implementation — the arch crate calls back into the kernel
// through these methods.
// ---------------------------------------------------------------------------

struct ArchInterfaceImpl;

#[crate_interface::impl_interface]
impl arch::api::ArchInterface for ArchInterfaceImpl {
    fn init_allocator() {}

    fn init_logging() {}

    fn add_memory_region(_start: usize, _end: usize) {}

    fn main(_hartid: usize) {}

    fn prepare_drivers() {}

    fn kernel_interrupt(trap_type: arch::TrapType) {
        crate::trap::kernel_interrupt_dispatch(trap_type);
    }

    fn frame_alloc() -> usize {
        let frame = match crate::mm::frame_alloc() {
            Some(f) => f,
            None => {
                error!("[OOM] frame_alloc failed in page table allocation");
                panic!("[OOM] kernel page table frame exhausted");
            }
        };
        let ppn = frame.ppn.0;
        core::mem::forget(frame);
        ppn
    }

    fn frame_dealloc(ppn: usize) {
        crate::mm::frame_dealloc(arch::PhysPageNum(ppn));
    }

    fn kernel_page_table_token() -> usize {
        crate::mm::kernel_page_table_token_if_ready()
    }
}

//! Kernel boot sequence.
//!
//! `rust_main` is the first Rust function called from the assembly entry
//! point (`_start` in `arch/src/riscv64/entry.asm` or the LoongArch64
//! equivalent).  It initializes all kernel subsystems and enters the
//! scheduler loop.

/// The Rust entry-point of the kernel (RISC-V 64).
#[cfg(target_arch = "riscv64")]
#[no_mangle]
pub fn rust_main() -> ! {
    arch::switch_to_kernel_page_table();
    unsafe {
        core::arch::asm!(
            "or sp, sp, {virt_base}",
            virt_base = in(reg) arch::VIRT_ADDR_START
        );
    }
    let entry_high = arch::kernel_text_addr(rust_main_high as usize);
    let entry: fn() -> ! = unsafe { core::mem::transmute(entry_high) };
    entry();
}

#[cfg(target_arch = "riscv64")]
#[inline(never)]
fn rust_main_high() -> ! {
    arch::clear_bss();
    crate::logging::init();
    crate::mm::init();
    // Under the high-half kernel execution model, the legacy remap_test
    // assumptions about section-level low-half mappings do not hold.
    // Keep boot path moving and add a dedicated high-half sanity check later.
    arch::trap_init();
    arch::trap_enable_timer_interrupt();
    crate::timer::set_next_trigger();
    crate::platform::platform_init();
    #[cfg(feature = "ext4")]
    if crate::fs::mount_ext4_auto() {
        info!("[kernel] ext4 mounted as root");
        crate::fs::ensure_busybox_links();
    } else if crate::fs::mount_fat32_auto() {
        info!("[kernel] fat32 mounted as root");
    } else {
        crate::fs::mount_easyfs();
    }
    #[cfg(not(feature = "ext4"))]
    if crate::fs::mount_fat32_auto() {
        info!("[kernel] fat32 mounted as root");
    } else {
        crate::fs::mount_easyfs();
    }
    crate::fs::mount_procfs();
    crate::fs::ensure_basic_paths();
    crate::fs::list_apps();
    crate::net::init();
    crate::task::add_initproc();
    #[cfg(target_arch = "riscv64")]
    {
        // Keep polling mode as default; allow opt-in via compile-time env for perf experiments.
        let use_non_blocking = option_env!("VIRTIO_BLK_NON_BLOCKING").is_some();
        *crate::DEV_NON_BLOCKING_ACCESS.exclusive_access() = use_non_blocking;
        info!(
            "[block] virtio non-blocking mode={}",
            if use_non_blocking { "on" } else { "off" }
        );
    }
    crate::task::run_tasks();
    panic!("Unreachable in rust_main!");
}

/// The Rust entry-point of the kernel (LoongArch64).
#[cfg(target_arch = "loongarch64")]
#[no_mangle]
pub fn rust_main() -> ! {
    arch::clear_bss();
    crate::logging::init();
    arch::init_interrupt();
    arch::trap_init();
    crate::mm::init();
    arch::init_timer();
    arch::trap_enable_timer_interrupt();
    crate::timer::set_next_trigger();
    crate::platform::platform_init();
    #[cfg(feature = "ext4")]
    if crate::fs::mount_ext4_auto() {
        info!("[kernel] ext4 mounted as root");
        crate::fs::ensure_busybox_links();
    } else if crate::fs::mount_fat32_auto() {
        info!("[kernel] fat32 mounted as root");
    } else {
        crate::fs::mount_easyfs();
    }
    #[cfg(not(feature = "ext4"))]
    if crate::fs::mount_fat32_auto() {
        info!("[kernel] fat32 mounted as root");
    } else {
        crate::fs::mount_easyfs();
    }
    crate::fs::mount_procfs();
    crate::fs::ensure_basic_paths();
    crate::fs::list_apps();
    crate::net::init();
    crate::task::add_initproc();
    crate::task::run_tasks();
    panic!("Unreachable in rust_main!");
}

