//! Implementation of [`MapArea`] and [`MemorySet`].
use super::address_space_policy;
use super::{frame_alloc, FrameTracker};
use super::{PTEFlags, PageTable, PageTableEntry};
use super::{PhysPageNum, VirtAddr, VirtPageNum};
use super::{StepByOne, VPNRange};
use crate::config::USER_STACK_TOP;
use crate::config::{PAGE_SIZE, USER_STACK_SIZE};
use crate::fs::File;
use crate::sync::UPIntrFreeCell;
use alloc::collections::BTreeMap;
use alloc::format;
use alloc::string::String;
use alloc::sync::Arc;
use alloc::vec::Vec;
use lazy_static::*;

lazy_static! {
    /// The kernel's initial memory mapping(kernel address space)
    pub static ref KERNEL_SPACE: Arc<UPIntrFreeCell<MemorySet>> =
        Arc::new(unsafe { UPIntrFreeCell::new(MemorySet::new_kernel()) });
    /// Global shared page cache for MAP_SHARED file-backed mmap pages.
    /// Keyed by `(file_id, page_offset)` so independent mmaps in different
    /// processes can map the same physical frame and observe each other's writes.
    static ref SHARED_FILE_PAGE_CACHE: UPIntrFreeCell<BTreeMap<SharedFilePageKey, Arc<FrameTracker>>> =
        unsafe { UPIntrFreeCell::new(BTreeMap::new()) };
}

#[derive(Clone, PartialEq, Eq, PartialOrd, Ord)]
struct SharedFilePageKey {
    file_id: String,
    page_offset: usize,
}

fn shared_file_id(file: &Arc<dyn File + Send + Sync>) -> Option<String> {
    if let Some(path) = file.path() {
        return Some(format!("path:{path}"));
    }
    file.inode()
        .map(|inode| format!("inode:{:p}", Arc::as_ptr(&inode)))
}

fn alloc_file_page_from_backing(
    file: &Arc<dyn File + Send + Sync>,
    page_offset: usize,
) -> Option<Arc<FrameTracker>> {
    let frame = frame_alloc()?;
    let mut frame = Arc::new(frame);
    let page = Arc::get_mut(&mut frame).unwrap().ppn.get_bytes_array();
    let nread = file.read_at_kernel(page_offset, page);
    if nread < PAGE_SIZE {
        page[nread..].fill(0);
    }
    Some(frame)
}

fn get_or_alloc_shared_file_page(
    file: &Arc<dyn File + Send + Sync>,
    page_offset: usize,
) -> Option<Arc<FrameTracker>> {
    let file_id = shared_file_id(file)?;
    let key = SharedFilePageKey {
        file_id,
        page_offset,
    };
    if let Some(frame) = SHARED_FILE_PAGE_CACHE.exclusive_access().get(&key).cloned() {
        return Some(frame);
    }
    let new_frame = alloc_file_page_from_backing(file, page_offset)?;
    let mut cache = SHARED_FILE_PAGE_CACHE.exclusive_access();
    if let Some(frame) = cache.get(&key).cloned() {
        return Some(frame);
    }
    cache.insert(key, new_frame.clone());
    Some(new_frame)
}

/// Invalidate cached shared mmap pages for a given path.
/// Used by truncate paths so a resized file does not reuse stale shared pages.
pub fn invalidate_shared_file_pages_by_path(path: &str) {
    let key_prefix = format!("path:{path}");
    SHARED_FILE_PAGE_CACHE
        .exclusive_access()
        .retain(|k, _| k.file_id != key_prefix);
}

/// the kernel token
pub fn kernel_token() -> usize {
    KERNEL_SPACE.exclusive_access().token()
}

/// address space
pub struct MemorySet {
    page_table: PageTable,
    areas: Vec<MapArea>,
}

/// Result classification for `mprotect()`-style permission changes.
#[derive(Copy, Clone, Debug, PartialEq, Eq)]
pub enum ProtectError {
    /// The requested range is not fully mapped.
    Unmapped,
    /// The underlying mapping does not permit the requested access.
    AccessDenied,
}

/// Error classes returned by `msync_file_range()`.
#[derive(Copy, Clone, Debug, PartialEq, Eq)]
pub enum MsyncError {
    /// `MS_INVALIDATE` was requested on a locked mapping.
    Busy,
    /// The target range does not overlap any mapped area.
    Unmapped,
}

#[derive(Copy, Clone, Eq, PartialEq, Debug)]
enum MapAreaKind {
    Private,
    Shared,
}

/// Type of memory area, used for precise identification and protection.
#[derive(Copy, Clone, Eq, PartialEq, Debug)]
pub enum MapAreaType {
    /// Kernel mapping (identical mapping)
    Kernel,
    /// ELF program segment (code, data, BSS)
    ElfSegment,
    /// Heap area (managed by sbrk/brk)
    Heap,
    /// User stack
    Stack,
    /// Anonymous mmap
    MmapAnon,
    /// File-backed mmap
    MmapFile,
    /// SysV shared memory
    Shm,
    /// Other/unknown
    Other,
}

impl MemorySet {
    /// Create a new empty `MemorySet`.
    pub fn new_bare() -> Self {
        Self {
            page_table: PageTable::new(),
            areas: Vec::new(),
        }
    }
    /// Get the page table token
    pub fn token(&self) -> usize {
        self.page_table.token()
    }
    /// Assume that no conflicts.
    pub fn insert_framed_area(
        &mut self,
        start_va: VirtAddr,
        end_va: VirtAddr,
        permission: MapPermission,
    ) {
        self.push(
            MapArea::new(start_va, end_va, MapType::Framed, permission),
            None,
        );
    }
    /// Insert a framed user area whose pages stay shared across `fork()`.
    pub fn insert_shared_framed_area(
        &mut self,
        start_va: VirtAddr,
        end_va: VirtAddr,
        permission: MapPermission,
    ) {
        self.push(
            MapArea::new(start_va, end_va, MapType::Framed, permission).with_shared_frames(),
            None,
        );
    }
    /// Insert a user mmap region with bookkeeping metadata.
    pub fn insert_mmap_area(
        &mut self,
        start_va: VirtAddr,
        end_va: VirtAddr,
        permission: MapPermission,
        meta: MmapMeta,
        area_type: MapAreaType,
    ) {
        let area = if meta.shared {
            MapArea::new_with_kind(
                start_va,
                end_va,
                MapType::Framed,
                permission,
                MapAreaKind::Shared,
            )
            .with_mmap_meta(meta)
            .with_shared_frames()
            .with_area_type(area_type)
        } else {
            MapArea::new_with_type(start_va, end_va, MapType::Framed, permission, area_type)
                .with_mmap_meta(meta)
        };
        if meta.shared {
            self.push(area, None);
        } else {
            self.push(area, None);
        }
    }
    /// Register an anonymous lazy VMA — no physical frames allocated until page fault.
    pub fn insert_lazy_anon_area(
        &mut self,
        start_va: VirtAddr,
        end_va: VirtAddr,
        permission: MapPermission,
        meta: MmapMeta,
    ) {
        let mut area = MapArea::new_lazy(start_va, end_va, permission)
            .with_mmap_meta(meta)
            .with_area_type(MapAreaType::MmapAnon);
        if meta.shared {
            area = area.with_kind(MapAreaKind::Shared).with_shared_frames();
        }
        self.areas.push(area);
    }
    /// Register a file-backed lazy VMA — pages populated from file on fault.
    pub fn insert_lazy_file_area(
        &mut self,
        start_va: VirtAddr,
        end_va: VirtAddr,
        permission: MapPermission,
        file: Arc<dyn File + Send + Sync>,
        file_offset: u64,
        meta: MmapMeta,
    ) {
        let mut area = MapArea::new_lazy_file(start_va, end_va, permission, file, file_offset)
            .with_mmap_meta(meta)
