//! RISC-V trap handling -- architecture layer.
//!
//! This implementation uses `kernelvec/uservec` with `sscratch` stack
//! switching and does not depend on trampoline-page trap entry.

mod context;

use crate::api::ArchInterface;
use crate::TrapType;
use core::arch::global_asm;
use riscv::register::{
    mtvec::TrapMode,
    scause::{self, Exception, Interrupt, Trap},
    sie, sscratch, stval, stvec,
};

global_asm!(include_str!("trap.S"));

extern "C" {
    fn kernelvec();
    fn riscv_user_enter(context: *mut u8, user_satp: usize);
}

/// Initialize trap handling: point `stvec` at `kernelvec`.
pub fn init() {
    let kernelvec_high = if (kernelvec as usize) >= crate::VIRT_ADDR_START {
        kernelvec as usize
    } else {
        (kernelvec as usize) | crate::VIRT_ADDR_START
    };
    unsafe {
        stvec::write(kernelvec_high, TrapMode::Direct);
        sscratch::write(0);
    }
}

/// Enable the supervisor timer interrupt (sets `sie.STIE`).
pub fn enable_timer_interrupt() {
    unsafe {
        sie::set_stimer();
    }
}

/// Enter user mode and return once a trap from user mode occurs.
pub fn enter_user_and_trap(context: &mut context::TrapContext, user_satp: usize) -> TrapType {
    let enter_high = if (riscv_user_enter as usize) >= crate::VIRT_ADDR_START {
        riscv_user_enter as usize
    } else {
        (riscv_user_enter as usize) | crate::VIRT_ADDR_START
    };
    let enter_fn: extern "C" fn(*mut u8, usize) = unsafe { core::mem::transmute(enter_high) };
    enter_fn((context as *mut _) as *mut u8, user_satp);
    classify_current_trap()
}

/// Called from `trap.S` for traps taken while already in supervisor mode.
#[no_mangle]
extern "C" fn kernel_trap_dispatch(_trap_cx: &context::KernelTrapContext) {
    let scause = scause::read();
    let stval = stval::read();

    let trap_type = match scause.cause() {
        Trap::Interrupt(Interrupt::SupervisorExternal) => TrapType::SupervisorExternal,
        Trap::Interrupt(Interrupt::SupervisorTimer) => TrapType::Time,
        Trap::Exception(Exception::Breakpoint) => TrapType::Breakpoint,
        _ => {
            error!(
                "[rv-ktrap] unsupported kernel trap: bits={:#x} cause={:?} stval={:#x} sepc={:#x} ra={:#x} sp={:#x} a0={:#x} a1={:#x} a2={:#x} a7={:#x}",
                scause.bits(),
                scause.cause(),
                stval,
                _trap_cx.sepc,
                _trap_cx.x[1],
                _trap_cx.x[2],
                _trap_cx.x[10],
                _trap_cx.x[11],
                _trap_cx.x[12],
                _trap_cx.x[17]
            );
            panic!(
                "Unsupported trap from kernel: {:?}, stval = {:#x}!",
                scause.cause(),
                stval
            );
        }
    };

    ArchInterface::kernel_interrupt(trap_type);
}

fn classify_current_trap() -> TrapType {
    let scause = scause::read();
    let stval = stval::read();
    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => TrapType::UserEnvCall,
        Trap::Exception(Exception::Breakpoint) => TrapType::Breakpoint,
        Trap::Interrupt(Interrupt::SupervisorTimer) => TrapType::Time,
        Trap::Interrupt(Interrupt::SupervisorExternal) => TrapType::SupervisorExternal,
        Trap::Exception(Exception::StoreFault) | Trap::Exception(Exception::StorePageFault) => {
            TrapType::StorePageFault(stval)
        }
        Trap::Exception(Exception::LoadFault) | Trap::Exception(Exception::LoadPageFault) => {
            TrapType::LoadPageFault(stval)
        }
        Trap::Exception(Exception::InstructionFault)
        | Trap::Exception(Exception::InstructionPageFault) => {
            TrapType::InstructionPageFault(stval)
        }
        Trap::Exception(Exception::IllegalInstruction) => TrapType::IllegalInstruction(stval),
        _ => TrapType::Unknown,
    }
}

pub use context::TrapContext;

use super::*;

pub(super) fn handle_user_supervisor_external() {
    crate::platform::handle_external_irq();
}

pub(super) fn handle_user_page_fault(addr: usize) {
    // Try COW first, then demand paging (both under the process lock)
    {
        let process = current_process();
        if process.handle_cow_or_demand_fault(addr) {
            return;
        }
    }

    // Not COW-able: log and SIGSEGV
    let trap_cx = current_trap_cx();
    error!(
        "[kernel] trap_handler: page fault addr={:#x} sepc={:#x} ra={:#x} sp={:#x} tp={:#x}",
        addr,
        trap_cx.sepc,
        trap_cx[TrapFrameArgs::RA],
        trap_cx[TrapFrameArgs::SP],
        trap_cx[TrapFrameArgs::TLS]
    );
    if let Some(task) = current_task() {
        // Synchronous faults should be delivered to the faulting thread.
        // If SIGSEGV stays masked, user mode can loop on the same fault forever.
        task.with_signals_mut(|signals| {
            signals.signal_mask.remove(SignalFlags::SIGSEGV);
            signals.signal_pending.insert(SignalFlags::SIGSEGV);
            signals.interrupted_by_signal = true;
        });
    } else {
        current_add_signal(SignalFlags::SIGSEGV);
    }
}

pub(super) fn handle_user_illegal_instruction(addr: usize) {
    let trap_cx = current_trap_cx();
    let sepc = trap_cx.sepc;
    let ra = trap_cx[TrapFrameArgs::RA];
    let sp = trap_cx[TrapFrameArgs::SP];
    let tp = trap_cx[TrapFrameArgs::TLS];
    let in_sigreturn_trampoline = arch::is_sigreturn_trampoline_pc(sepc);

    if let Some(task) = current_task() {
        let pid = current_process().pid.0;
        let tid = task.tid();
        let handling_sig = task.handling_sig();
        let repeat = task.record_illegal_instruction(sepc);

        // Synchronous illegal-instruction trap should be delivered to the faulting task.
        task.with_signals_mut(|signals| {
            signals.signal_mask.remove(SignalFlags::SIGILL);
            signals.signal_pending.insert(SignalFlags::SIGILL);
            signals.interrupted_by_signal = true;
        });

        let fatal_sigreturn_loop = in_sigreturn_trampoline && handling_sig != -1;

        if fatal_sigreturn_loop {
            warn!(
                "[kernel] trap_handler: illegal instruction in sigreturn trampoline, pid={} tid={} sepc={:#x} ra={:#x} sp={:#x} tp={:#x} handling_sig={} -> force exit",
                pid, tid, sepc, ra, sp, tp, handling_sig
            );
            crate::task::exit_current_and_run_next(-(crate::task::SIGILL as i32));
            panic!("Unreachable after fatal illegal instruction in sigreturn trampoline");
        }

        if repeat == 1 {
            let level = if in_sigreturn_trampoline {
                "[warn/sigtrx]"
            } else {
                "[error]"
            };
            if in_sigreturn_trampoline {
                warn!(
                    "{} [kernel] trap_handler: illegal instruction addr={:#x} sepc={:#x} ra={:#x} sp={:#x} tp={:#x} pid={} tid={}",
                    level, addr, sepc, ra, sp, tp, pid, tid
                );
            } else {
                error!(
                    "{} [kernel] trap_handler: illegal instruction addr={:#x} sepc={:#x} ra={:#x} sp={:#x} tp={:#x} pid={} tid={}",
                    level, addr, sepc, ra, sp, tp, pid, tid
                );
            }
        } else if repeat % 128 == 0 {
            warn!(
                "[kernel] trap_handler: repeated illegal instruction suppressed pid={} tid={} sepc={:#x} repeat={}",
                pid, tid, sepc, repeat
            );
        }
        return;
    }

    if in_sigreturn_trampoline {
        warn!(
            "[kernel] trap_handler: illegal instruction addr={:#x} sepc={:#x} ra={:#x} sp={:#x} tp={:#x}",
            addr, sepc, ra, sp, tp
        );
    } else {
        error!(
            "[kernel] trap_handler: illegal instruction addr={:#x} sepc={:#x} ra={:#x} sp={:#x} tp={:#x}",
            addr, sepc, ra, sp, tp
        );
    }
    current_add_signal(SignalFlags::SIGILL);
}

pub(super) fn handle_user_breakpoint() {
    let user_token = current_user_token();
    let trap_cx = current_trap_cx();
    if let Some(next_pc) = arch::breakpoint_next_pc(user_token, trap_cx.sepc) {
        trap_cx.sepc = next_pc;
    }
}

pub(super) fn handle_user_unknown_trap(trap_type: arch::TrapType) {
    let trap_cx = current_trap_cx();
