/// Check if a path is a character device.
fn is_char_device(path: &str) -> bool {
    matches!(
        path,
        "/dev/null"
            | "/dev/zero"
            | "/dev/tty"
            | "/dev/urandom"
            | "/dev/random"
            | "/dev/rtc"
            | "/dev/rtc0"
            | "/dev/misc/rtc"
    )
}

fn rdev_for_path(path: &str) -> u64 {
    match path {
        "/dev/null" => 0x0103,
        "/dev/zero" => 0x0105,
        "/dev/tty" => 0x0500,
        "/dev/urandom" | "/dev/random" => 0x0109,
        _ => 0,
    }
}

