fn metadata_for_path(path: &str) -> Option<VfsMetadata> {
    inode_for_path(path).and_then(|inode| inode.metadata())
}

fn effective_path_owner(path: &str) -> (u32, u32) {
    metadata_for_path(path)
        .map(|metadata| (metadata.uid, metadata.gid))
        .unwrap_or((0, 0))

