#[derive(Clone, Copy)]
struct SchedState {
    policy: i32,
    priority: i32,
    nice: i32,
    flags: u64,
    runtime: u64,
    deadline: u64,
    period: u64,
    reset_on_fork: bool,
}

impl Default for SchedState {
    fn default() -> Self {
        Self {
            policy: SCHED_OTHER,
            priority: 0,
            nice: 0,
            flags: 0,
            runtime: 0,
            deadline: 0,
            period: 0,
            reset_on_fork: false,
        }
    }
}

pub fn sched_reset_process_state(pid: usize) {
    SCHED_STATE.exclusive_access().remove(&pid);
}

pub fn sched_inherit_for_fork(parent_pid: usize, child_pid: usize) {
    let parent = sched_state_for(parent_pid);
    let child = if parent.reset_on_fork {
        SchedState::default()
    } else {
        parent
    };
    let mut states = SCHED_STATE.exclusive_access();
    if matches!(child.policy, SCHED_OTHER) && child.priority == 0 && !child.reset_on_fork {
        states.remove(&child_pid);
    } else {
        states.insert(child_pid, child);
    }
}

#[allow(dead_code)]
fn dump_user_bytes(tag: &str, token: usize, addr: usize, len: usize) {
    let page_table = PageTable::from_token(token);
    let end = addr.saturating_add(len);
    let mut cur = addr;
    while cur < end {
        let mut line = [0u8; 16];
        let mut any = false;
        let line_end = core::cmp::min(cur + 16, end);
        for i in 0..(line_end - cur) {
            let va = cur + i;
            if let Some(pa) = page_table.translate_va(VirtAddr::from(va)) {
                line[i] = *pa.get_ref::<u8>();
                any = true;
            }
        }
        if any {
            info!(
                "[clone-tls] {} {:#x}: {:02x?}",
                tag,
                cur,
                &line[..(line_end - cur)]
            );
        } else {
            info!("[clone-tls] {} {:#x}: <unmapped>", tag, cur);
        }
        cur += 16;
    }
}

