pub trait VfsInode: Send + Sync {
    fn kind(&self) -> VfsNodeKind;
    fn read_at(&self, offset: usize, buf: &mut [u8]) -> usize;
    fn write_at(&self, offset: usize, buf: &[u8]) -> usize;
    fn lookup(&self, name: &str) -> Option<Arc<dyn VfsInode>>;
    fn create(&self, name: &str) -> Option<Arc<dyn VfsInode>>;
    fn create_dir(&self, _name: &str) -> Option<Arc<dyn VfsInode>> {
        None
    }
    fn remove(&self, _name: &str, _is_dir: bool) -> bool {
        false
    }
    fn truncate(&self);
    /// Truncate (or extend) file to exactly `size` bytes.
    /// Default: truncate-to-zero for size==0, grow via write for size>current, shrink via truncate+rewrite otherwise.
    fn truncate_to(&self, size: usize) {
        let current = self.size();
        if size == current {
            return;
        }
        if size == 0 {
            self.truncate();
            return;
        }
        if size > current {
            // Extend: write a single zero byte at offset size-1.
            // write_at handles the gap fill with zeros internally.
            self.write_at(size - 1, &[0u8; 1]);
        } else {
            // Shrink: default = truncate to zero then re-write up to size.
            // Subclasses (Ext4Inode) override this for real ftruncate.
            self.truncate();
        }
    }
    fn list(&self) -> Vec<String>;
    fn size(&self) -> usize {
        0
    }

    fn metadata(&self) -> Option<VfsMetadata> {
        None
    }

    fn chmod(&self, _mode: u32) -> Result<(), isize> {
        Err(-95)
    }

    fn chown(&self, _uid: Option<u32>, _gid: Option<u32>) -> Result<(), isize> {
        Err(-95)
    }

    fn utimens(&self, _atime_sec: Option<i64>, _mtime_sec: Option<i64>) -> Result<(), isize> {
        Err(-95)
    }

    fn link_to(&self, _new_path: &str) -> Result<(), isize> {
        Err(-95)
    }

    fn symlink(&self, _name: &str, _target: &str) -> Result<Arc<dyn VfsInode>, isize> {
        Err(-95)
    }

    fn readlink(&self) -> Result<Vec<u8>, isize> {
        Err(-95)
    }

    fn mknod(&self, _name: &str, _mode: u32, _dev: u32) -> Result<Arc<dyn VfsInode>, isize> {
        Err(-95)
    }

    fn setxattr(&self, _name: &str, _value: &[u8]) -> Result<(), isize> {
        Err(-95)
    }

    fn getxattr(&self, _name: &str) -> Result<Vec<u8>, isize> {
        Err(-95)
    }

    fn listxattr(&self) -> Result<Vec<u8>, isize> {
        Err(-95)
    }

    fn removexattr(&self, _name: &str) -> Result<(), isize> {
        Err(-95)
    }

    fn statfs(&self) -> Option<VfsStatFs> {
        None
    }

    fn is_dir(&self) -> bool {
        self.kind() == VfsNodeKind::Dir
    }
}

