        if let Some(node) = self.entries.get(name) {
            return Some(node.clone());
        }
        if name == "self" {
            return Some(ProcPidDirInode::new(current_process().getpid()));
        }
        let pid = name.parse::<usize>().ok()?;
        pid2process(pid)?;
        Some(ProcPidDirInode::new(pid))
    }

