pub struct Fat32Inode {
    path: String,
    kind: VfsNodeKind,
    fs: Arc<UPIntrFreeCell<Fat32Fs>>,
}

impl Fat32Inode {
    pub(super) fn new(path: String, kind: VfsNodeKind, fs: Arc<UPIntrFreeCell<Fat32Fs>>) -> Self {
        Self { path, kind, fs }
    }

    pub(super) fn new_dir(path: String, fs: Arc<UPIntrFreeCell<Fat32Fs>>) -> Self {
        Self::new(path, VfsNodeKind::Dir, fs)
    }

    pub(super) fn new_file(path: String, fs: Arc<UPIntrFreeCell<Fat32Fs>>) -> Self {
        Self::new(path, VfsNodeKind::File, fs)
    }
}

type Fat32Dir<'a> = Dir<'a, super::disk::Fat32Disk, DefaultTimeProvider, LossyOemCpConverter>;
type Fat32File<'a> = File<'a, super::disk::Fat32Disk, DefaultTimeProvider, LossyOemCpConverter>;

type Fat32Result<T> = Result<T, Error<Fat32IoError>>;

fn fat32_rel_path(path: &str) -> &str {
    path.trim_start_matches('/')
}

fn fat32_path_join(base: &str, name: &str) -> String {
    if base == "/" {
        format!("/{}", name)
    } else {
        format!("{}/{}", base.trim_end_matches('/'), name)
    }
}

fn fat32_open_dir<'a>(fs: &'a Fat32Fs, path: &str) -> Fat32Result<Fat32Dir<'a>> {
    let root = fs.root_dir();
    let rel = fat32_rel_path(path);
    if rel.is_empty() {
        Ok(root)
    } else {
        root.open_dir(rel)
    }
}

fn fat32_open_file<'a>(fs: &'a Fat32Fs, path: &str) -> Fat32Result<Fat32File<'a>> {
    let root = fs.root_dir();
    let rel = fat32_rel_path(path);
    if rel.is_empty() {
        Err(Error::InvalidInput)
    } else {
        root.open_file(rel)
    }
}

fn fat32_create_file<'a>(fs: &'a Fat32Fs, path: &str) -> Fat32Result<Fat32File<'a>> {
    let root = fs.root_dir();
    let rel = fat32_rel_path(path);
    if rel.is_empty() {
        Err(Error::InvalidInput)
    } else {
        root.create_file(rel)
    }
}

impl VfsInode for Fat32Inode {
    fn kind(&self) -> VfsNodeKind {
        self.kind
    }

    fn read_at(&self, offset: usize, buf: &mut [u8]) -> usize {
        if self.kind != VfsNodeKind::File {
            return 0;
        }
        let fs = self.fs.exclusive_access();
        let mut file = match fat32_open_file(&fs, &self.path) {
            Ok(file) => file,
            Err(_) => return 0,
        };
        if file.seek(SeekFrom::Start(offset as u64)).is_err() {
            return 0;
        }
        Read::read(&mut file, buf).unwrap_or(0)
    }

    fn write_at(&self, offset: usize, buf: &[u8]) -> usize {
        if self.kind != VfsNodeKind::File {
            return 0;
        }
        let fs = self.fs.exclusive_access();
        let mut file = match fat32_open_file(&fs, &self.path) {
            Ok(file) => file,
            Err(Error::NotFound) => match fat32_create_file(&fs, &self.path) {
                Ok(file) => file,
                Err(_) => return 0,
            },
            Err(_) => return 0,
        };
        if file.seek(SeekFrom::Start(offset as u64)).is_err() {
            return 0;
        }
        Write::write(&mut file, buf).unwrap_or(0)
    }

    fn lookup(&self, name: &str) -> Option<Arc<dyn VfsInode>> {
        if self.kind != VfsNodeKind::Dir {
            return None;
        }
        let path = fat32_path_join(self.path.as_str(), name);
        let fs = self.fs.exclusive_access();
        if fat32_open_dir(&fs, &path).is_ok() {
            Some(Arc::new(Fat32Inode::new_dir(path, self.fs.clone())) as Arc<dyn VfsInode>)
        } else if fat32_open_file(&fs, &path).is_ok() {
            Some(Arc::new(Fat32Inode::new_file(path, self.fs.clone())) as Arc<dyn VfsInode>)
        } else {
            None
        }
    }

    fn create(&self, name: &str) -> Option<Arc<dyn VfsInode>> {
        if self.kind != VfsNodeKind::Dir {
            return None;
        }
        let path = fat32_path_join(self.path.as_str(), name);
        let fs = self.fs.exclusive_access();
        fat32_create_file(&fs, &path).ok()?;
        Some(Arc::new(Fat32Inode::new_file(path, self.fs.clone())) as Arc<dyn VfsInode>)
    }

    fn create_dir(&self, name: &str) -> Option<Arc<dyn VfsInode>> {
        if self.kind != VfsNodeKind::Dir {
            return None;
        }
        let path = fat32_path_join(self.path.as_str(), name);
        let fs = self.fs.exclusive_access();
        let root = fs.root_dir();
        let rel = fat32_rel_path(&path);
        if root.create_dir(rel).is_err() {
            return None;
        }
        Some(Arc::new(Fat32Inode::new_dir(path, self.fs.clone())) as Arc<dyn VfsInode>)
    }

    fn remove(&self, name: &str, _is_dir: bool) -> bool {
        if self.kind != VfsNodeKind::Dir {
            return false;
        }
        let fs = self.fs.exclusive_access();
        let dir = match fat32_open_dir(&fs, &self.path) {
            Ok(dir) => dir,
            Err(_) => return false,
        };
        dir.remove(name).is_ok()
    }

    fn truncate(&self) {
        if self.kind != VfsNodeKind::File {
            return;
        }
        let fs = self.fs.exclusive_access();
        let mut file = match fat32_open_file(&fs, &self.path) {
            Ok(file) => file,
            Err(_) => return,
        };
        if file.seek(SeekFrom::Start(0)).is_err() {
            return;
        }
        let _ = file.truncate();
    }

    fn list(&self) -> Vec<String> {
        if self.kind != VfsNodeKind::Dir {
            return Vec::new();
        }
        let fs = self.fs.exclusive_access();
        let dir = match fat32_open_dir(&fs, &self.path) {
            Ok(dir) => dir,
            Err(_) => return Vec::new(),
        };
        let mut names = Vec::new();
        for entry in dir.iter() {
            let entry = match entry {
                Ok(entry) => entry,
                Err(_) => continue,
            };
            let name = entry.file_name();
            if name == "." || name == ".." {
                continue;
            }
            names.push(name);
        }
        names
    }

    fn size(&self) -> usize {
        if self.kind != VfsNodeKind::File {
            return 0;
        }
        let fs = self.fs.exclusive_access();
        let mut file = match fat32_open_file(&fs, &self.path) {
            Ok(file) => file,
            Err(_) => return 0,
        };
        file.seek(SeekFrom::End(0)).ok().unwrap_or(0) as usize
    }
}

//! Cached Block Device Wrapper
//!
//! This module provides a caching layer for any BlockDevice implementation.
//! It significantly improves file system performance by reducing direct I/O operations.

use super::BlockDevice;
use alloc::collections::{BTreeMap, VecDeque};
use alloc::sync::Arc;
use alloc::vec::Vec;
use core::sync::atomic::{AtomicBool, AtomicU64, Ordering};
use spin::Mutex;

/// Logical block size used by the block device API.
const BLOCK_SIZE: usize = 512;
/// Cache entry granularity (one cached page contains multiple logical blocks).
const CACHE_PAGE_SIZE: usize = 16 * 1024;
const BLOCKS_PER_PAGE: usize = CACHE_PAGE_SIZE / BLOCK_SIZE;

const fn parse_cache_size(value: &str) -> Option<usize> {
    let bytes = value.as_bytes();
    let mut out: usize = 0;
    let mut i = 0usize;
    while i < bytes.len() {
        let b = bytes[i];
        if b < b'0' || b > b'9' {
            return None;
        }
        out = out.saturating_mul(10).saturating_add((b - b'0') as usize);
        i += 1;
    }
    Some(out)
}

const fn cache_size_blocks_from_env() -> usize {
    match option_env!("BLOCK_CACHE_SIZE") {
        Some(v) => match parse_cache_size(v) {
            Some(0) | None => 16_384,
            Some(n) => n,
        },
        // Default: 16384 blocks * 512B = 8MB (reduced from 24MB to ease heap pressure).
        None => 16_384,
    }
}

const fn cache_page_capacity_from_blocks(blocks: usize) -> usize {
    let pages = (blocks + BLOCKS_PER_PAGE - 1) / BLOCKS_PER_PAGE;
    if pages == 0 {
        1
    } else {
        pages
    }
}

/// Cache capacity in logical 512-byte blocks (compatible with old meaning).
const CACHE_SIZE_BLOCKS: usize = cache_size_blocks_from_env();
/// Actual cache entry capacity in 16KiB pages.
const CACHE_PAGE_CAPACITY: usize = cache_page_capacity_from_blocks(CACHE_SIZE_BLOCKS);

const TRACE_BLOCK_CACHE_STATS: bool = option_env!("TRACE_BLOCK_CACHE_STATS").is_some();
const BLOCK_CACHE_WRITE_THROUGH: bool = option_env!("BLOCK_CACHE_WRITE_THROUGH").is_some();
const CACHE_STATS_LOG_EVERY_GETS: u64 = 20_000;
const CACHE_PRESSURE_WARN_BURST: u64 = 1;
const CACHE_PRESSURE_WARN_EVERY: u64 = 4096;

static CACHE_GET_CALLS: AtomicU64 = AtomicU64::new(0);
static CACHE_HIT_CALLS: AtomicU64 = AtomicU64::new(0);
static CACHE_MISS_CALLS: AtomicU64 = AtomicU64::new(0);
static CACHE_EVICT_CALLS: AtomicU64 = AtomicU64::new(0);
static CACHE_DIRTY_EVICT_CALLS: AtomicU64 = AtomicU64::new(0);
static CACHE_BACKEND_READS: AtomicU64 = AtomicU64::new(0);
static CACHE_BACKEND_WRITES: AtomicU64 = AtomicU64::new(0);
static CACHE_LAST_LOG_STEP: AtomicU64 = AtomicU64::new(0);
static CACHE_FULL_WARN_COUNT: AtomicU64 = AtomicU64::new(0);

#[inline]
fn maybe_log_cache_stats() {
    if !TRACE_BLOCK_CACHE_STATS {
        return;
    }
    let gets = CACHE_GET_CALLS.load(Ordering::Relaxed);
    if gets == 0 {
        return;
    }
    let step = gets / CACHE_STATS_LOG_EVERY_GETS;
    if step == 0 {
        return;
    }
    let mut prev = CACHE_LAST_LOG_STEP.load(Ordering::Relaxed);
    while step > prev {
        match CACHE_LAST_LOG_STEP.compare_exchange_weak(
            prev,
            step,
            Ordering::Relaxed,
            Ordering::Relaxed,
        ) {
            Ok(_) => {
                let hits = CACHE_HIT_CALLS.load(Ordering::Relaxed);
                let misses = CACHE_MISS_CALLS.load(Ordering::Relaxed);
                let hit_pct = if gets == 0 {
                    0
                } else {
                    hits.saturating_mul(100) / gets
                };
                info!(
                    "[blk-cache] t_ms={} gets={} hit={} miss={} hit_pct={} evict={} dirty_evict={} backend_read={} backend_write={} page_cap={} blk_cap={}",
                    crate::timer::get_time_ms(),
                    gets,
                    hits,
                    misses,
                    hit_pct,
                    CACHE_EVICT_CALLS.load(Ordering::Relaxed),
                    CACHE_DIRTY_EVICT_CALLS.load(Ordering::Relaxed),
                    CACHE_BACKEND_READS.load(Ordering::Relaxed),
                    CACHE_BACKEND_WRITES.load(Ordering::Relaxed),
                    CACHE_PAGE_CAPACITY,
                    CACHE_SIZE_BLOCKS,
                );
                break;
            }
            Err(actual) => prev = actual,
        }
    }
}

#[inline]
fn maybe_warn_cache_pressure() {
    let forced = CACHE_FULL_WARN_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
    if forced <= CACHE_PRESSURE_WARN_BURST || forced % CACHE_PRESSURE_WARN_EVERY == 0 {
        warn!(
            "Cache full with all pages recently used/in use, forcing eviction (count={})",
            forced
        );
    }
}

#[inline]
const fn page_id_of(block_id: usize) -> usize {
    block_id / BLOCKS_PER_PAGE
}

#[inline]
const fn block_off_in_page(block_id: usize) -> usize {
    block_id % BLOCKS_PER_PAGE
}

#[inline]
const fn block_mask(block_off: usize) -> u64 {
    1u64 << block_off
}

//! VirtIO network device driver adapted for smoltcp.

use alloc::vec;
use alloc::vec::Vec;

use crate::drivers::bus::virtio::VirtioHal;
use arch::DeviceKind;
use smoltcp::phy::{self, Device, DeviceCapabilities, Medium};
use smoltcp::time::Instant;
use virtio_drivers::{DeviceType, VirtIOHeader, VirtIONet};

/// Maximum Ethernet frame size (MTU 1500 + header 14).
const ETH_FRAME_SIZE: usize = 1514;

/// VirtIO network device implementing smoltcp's Device trait.
pub struct VirtIONetDevice {
    inner: VirtIONet<'static, VirtioHal>,
    rx_buf: Vec<u8>,
}

impl VirtIONetDevice {
    fn header_at(addr: usize) -> Option<&'static mut VirtIOHeader> {
        let header = unsafe { &mut *(addr as *mut VirtIOHeader) };
        if header.verify() && header.device_type() == DeviceType::Network {
            Some(header)
        } else {
            None
        }
    }

    fn find_virtio_net_header() -> Option<&'static mut VirtIOHeader> {
        let addr = arch::platform_config()
            .device(DeviceKind::Net)
            .and_then(|device| device.mmio_base())
            .expect("VirtIO net MMIO base missing from platform config");
        if let Some(header) = Self::header_at(addr) {
            log::info!("[net] found virtio-net mmio at {:#x}", addr);
            return Some(header);
        }

        for device in arch::platform_config().devices {
            match device.kind {
                DeviceKind::Block
                | DeviceKind::Net
                | DeviceKind::InputKeyboard
                | DeviceKind::InputMouse => {}
                _ => continue,
            }
            if let Some(probe) = device.mmio_base() {
                if probe != addr {
                    if let Some(header) = Self::header_at(probe) {
                        log::info!("[net] found virtio-net mmio at {:#x}", probe);
                        return Some(header);
                    }
                }
            }
        }

        log::warn!("[net] virtio-net mmio device not found");
        None
    }

    /// Create a new VirtIO network device.
    pub fn try_new() -> Option<Self> {
        let header = Self::find_virtio_net_header()?;
        let inner = match VirtIONet::<VirtioHal>::new(header) {
            Ok(inner) => inner,
            Err(err) => {
                log::warn!("[net] failed to create virtio-net device: {:?}", err);
                return None;
            }
        };
        Some(Self {
            inner,
            rx_buf: vec![0u8; 2048],
        })
    }

    /// Get the MAC address from VirtIO config space.
    pub fn mac_address(&self) -> [u8; 6] {
        self.inner.mac()
    }
}

/// Receive token: holds the received frame data in an owned buffer.
pub struct VirtioRxToken {
    buf: Vec<u8>,
}

impl phy::RxToken for VirtioRxToken {
    fn consume<R, F>(mut self, f: F) -> R
    where
        F: FnOnce(&mut [u8]) -> R,
    {
        f(&mut self.buf)
    }
}

/// Transmit token: allocates a buffer, lets smoltcp fill it, then sends.
pub struct VirtioTxToken<'a> {
    driver: &'a mut VirtIONet<'static, VirtioHal>,
}

impl<'a> phy::TxToken for VirtioTxToken<'a> {
    fn consume<R, F>(self, len: usize, f: F) -> R
    where
        F: FnOnce(&mut [u8]) -> R,
    {
        let mut buf = vec![0u8; len];
        let result = f(&mut buf);
        if let Err(e) = self.driver.send(&buf) {
            log::warn!("[net] virtio-net send failed: {:?}", e);
        }
        result
    }
}

impl Device for VirtIONetDevice {
    type RxToken<'a> = VirtioRxToken where Self: 'a;
    type TxToken<'a> = VirtioTxToken<'a> where Self: 'a;

    fn receive(&mut self, _timestamp: Instant) -> Option<(Self::RxToken<'_>, Self::TxToken<'_>)> {
        if !self.inner.can_recv() {
            return None;
        }
        match self.inner.recv(&mut self.rx_buf) {
            Ok(len) => {
                // Copy received data into an owned buffer for the RxToken
                let data = self.rx_buf[..len].to_vec();
                Some((
                    VirtioRxToken { buf: data },
                    VirtioTxToken {
                        driver: &mut self.inner,
                    },
                ))
            }
            Err(e) => {
                log::warn!("[net] virtio-net recv failed: {:?}", e);
                None
            }
        }
    }

    fn transmit(&mut self, _timestamp: Instant) -> Option<Self::TxToken<'_>> {
        if self.inner.can_send() {
            Some(VirtioTxToken {
                driver: &mut self.inner,
            })
        } else {
            None
        }
    }

    fn capabilities(&self) -> DeviceCapabilities {
        let mut caps = DeviceCapabilities::default();
        caps.medium = Medium::Ethernet;
        caps.max_transmission_unit = ETH_FRAME_SIZE;
        caps.max_burst_size = Some(1);
        caps
    }
}

use crate::drivers::bus::virtio::VirtioHal;
use crate::sync::{Condvar, UPIntrFreeCell};
use crate::task::schedule;
use alloc::collections::VecDeque;
use alloc::sync::Arc;
use arch::DeviceKind;
use core::any::Any;
use virtio_drivers::{VirtIOHeader, VirtIOInput};

struct VirtIOInputInner {
    virtio_input: VirtIOInput<'static, VirtioHal>,
    events: VecDeque<u64>,
}

struct VirtIOInputWrapper {
    inner: UPIntrFreeCell<VirtIOInputInner>,
    condvar: Condvar,
}

/// Input device interface.
pub trait InputDevice: Send + Sync + Any {
    /// Read a single input event.
    fn read_event(&self) -> u64;
    /// Handle device interrupt.
    fn handle_irq(&self);
    /// Whether the device event queue is empty.
    fn is_empty(&self) -> bool;
}

lazy_static::lazy_static!(
    /// Global keyboard input device.
    pub static ref KEYBOARD_DEVICE: Arc<dyn InputDevice> =
        Arc::new(VirtIOInputWrapper::new(input_base(DeviceKind::InputKeyboard)));
    /// Global mouse input device.
    pub static ref MOUSE_DEVICE: Arc<dyn InputDevice> =
        Arc::new(VirtIOInputWrapper::new(input_base(DeviceKind::InputMouse)));
);

fn input_base(kind: DeviceKind) -> usize {
    arch::platform_config()
        .device(kind)
        .and_then(|device| device.mmio_base())
        .expect("VirtIO input MMIO base missing from platform config")
}

impl VirtIOInputWrapper {
    pub fn new(addr: usize) -> Self {
        let inner = VirtIOInputInner {
            virtio_input: unsafe {
                VirtIOInput::<VirtioHal>::new(&mut *(addr as *mut VirtIOHeader)).unwrap()
            },
            events: VecDeque::new(),
        };
        Self {
            inner: unsafe { UPIntrFreeCell::new(inner) },
            condvar: Condvar::new(),
        }
    }
}

impl InputDevice for VirtIOInputWrapper {
    fn is_empty(&self) -> bool {
        self.inner.exclusive_access().events.is_empty()
    }

    fn read_event(&self) -> u64 {
        loop {
            let mut inner = self.inner.exclusive_access();
            if let Some(event) = inner.events.pop_front() {
                return event;
            } else {
                let task_cx_ptr = self.condvar.wait_no_sched();
                drop(inner);
                schedule(task_cx_ptr);
            }
        }
    }

    fn handle_irq(&self) {
        let mut count = 0;
        let mut result = 0;
        self.inner.exclusive_session(|inner| {
            inner.virtio_input.ack_interrupt();
            while let Some(event) = inner.virtio_input.pop_pending_event() {
                count += 1;
                result = (event.event_type as u64) << 48
                    | (event.code as u64) << 32
                    | (event.value) as u64;
                inner.events.push_back(result);
            }
        });
        if count > 0 {
            self.condvar.signal();
        };
    }
}

//! Uniprocessor interior mutability primitives
use arch::{disable_interrupts, enable_interrupts, interrupts_enabled};
use core::any::type_name;
use core::cell::{Ref, RefCell, RefMut, UnsafeCell};
use core::ops::{Deref, DerefMut};
use lazy_static::lazy_static;

/// Wrap a static data structure inside it so that we are
/// able to access it without any `unsafe`.
///
/// We should only use it in uniprocessor.
///
/// In order to get mutable reference of inner data, call
/// `exclusive_access`.
pub struct UPSafeCell<T> {
    /// inner data
    inner: RefCell<T>,
}

unsafe impl<T> Sync for UPSafeCell<T> {}
unsafe impl<T> Send for UPSafeCell<T> {}

impl<T> UPSafeCell<T> {
    /// User is responsible to guarantee that inner struct is only used in
    /// uniprocessor.
    pub unsafe fn new(value: T) -> Self {
        Self {
            inner: RefCell::new(value),
        }
    }
    /// Panic if the data has been borrowed.
    pub fn exclusive_access(&self) -> RefMut<'_, T> {
        self.inner.borrow_mut()
    }

    /// Try to borrow the inner value; returns None if already borrowed.
    pub fn try_exclusive_access(&self) -> Option<RefMut<'_, T>> {
        self.inner.try_borrow_mut().ok()
    }
}

struct UPSafeCellRaw<T> {
    inner: UnsafeCell<T>,
}

unsafe impl<T> Sync for UPSafeCellRaw<T> {}

impl<T> UPSafeCellRaw<T> {
    pub unsafe fn new(value: T) -> Self {
        Self {
            inner: UnsafeCell::new(value),
        }
    }

    pub fn get_mut(&self) -> &mut T {
        unsafe { &mut (*self.inner.get()) }
    }
}

struct IntrMaskingInfo {
    nested_level: usize,
    sie_before_masking: bool,
}

#[derive(Copy, Clone)]
struct BorrowSite {
    file: &'static str,
    line: u32,
}

lazy_static! {
    static ref INTR_MASKING_INFO: UPSafeCellRaw<IntrMaskingInfo> =
        unsafe { UPSafeCellRaw::new(IntrMaskingInfo::new()) };
}

impl IntrMaskingInfo {
    pub fn new() -> Self {
        Self {
            nested_level: 0,
            sie_before_masking: false,
        }
    }

    pub fn enter(&mut self) {
        let sie = interrupts_enabled();
        disable_interrupts();
        if self.nested_level == 0 {
            self.sie_before_masking = sie;
        }
        self.nested_level += 1;
    }

    pub fn exit(&mut self) {
        self.nested_level -= 1;
        if self.nested_level == 0 && self.sie_before_masking {
            enable_interrupts();
        }
    }
}

/// Interior-mutable cell that masks S-mode interrupts on access.
pub struct UPIntrFreeCell<T> {
    inner: RefCell<T>,
    last_borrow_site: UnsafeCell<Option<BorrowSite>>,
}

unsafe impl<T> Sync for UPIntrFreeCell<T> {}
unsafe impl<T> Send for UPIntrFreeCell<T> {}

/// RAII guard that automatically unmasks interrupts when dropped.
pub struct UPIntrRef<'a, T> {
    inner: Option<Ref<'a, T>>,
    borrow_site: *mut Option<BorrowSite>,
}

/// RAII guard that automatically unmasks interrupts when dropped.
pub struct UPIntrRefMut<'a, T> {
    inner: Option<RefMut<'a, T>>,
    borrow_site: *mut Option<BorrowSite>,
}

/// Guard returned by [`UPIntrMutex::lock`].
pub type UPIntrMutexGuard<'a, T> = UPIntrRefMut<'a, T>;
/// Shared guard returned by [`UPIntrRwLock::read`].
pub type UPIntrRwLockReadGuard<'a, T> = UPIntrRef<'a, T>;
/// Exclusive guard returned by [`UPIntrRwLock::write`].
pub type UPIntrRwLockWriteGuard<'a, T> = UPIntrRefMut<'a, T>;

impl<T> UPIntrFreeCell<T> {
    /// Create a new interrupt-masking cell.
    pub unsafe fn new(value: T) -> Self {
        Self {
            inner: RefCell::new(value),
            last_borrow_site: UnsafeCell::new(None),
